import React from 'react';
import './style.css';

const Hooks = () => {
  const [count, setCount] = React.useState(1);

  return (
    <main className="hooks-page">
      <section className="hooks-card">
        <p className="hooks-kicker">React Hooks</p>
        <h1>useState Example</h1>
        <p className="hooks-text">
          This simple counter shows how <code>useState</code> stores a value and updates the UI
          when the value changes.
        </p>

        <div className="hooks-counter">
          <span>{count}</span>
        </div>

        <div className="hooks-actions">
          <button
            type="button"
            className="hooks-button secondary"
            onClick={() => setCount(count - 1)}
          >
            Decrease
          </button>
          <button
            type="button"
            className="hooks-button primary"
            onClick={() => setCount(count + 1)}
          >
            Increase
          </button>
        </div>
      </section>
    </main>
  );
};

export default Hooks;
